// Solar-Beschattung: liest SENEC-Daten und schickt MQTT-Positionskommandos.
// Nur Erdgeschoss: Kueche2, GaesteBad, Wohnzimmer1 (getestet 12.07.2026).
const cfg = {
    shadeOnW: 2500,
    shadePos: 50,
    openPos: 100,
    eastStartHour: 7,
    eastEndHour: 13,
    westEndHour: 20.5,
};

function decodeSenecValue(data) {
    if (data === undefined || data === null) return NaN;
    if (typeof data === 'number') return data;
    if (typeof data !== 'string') return NaN;
    const tmp = data.split('_');
    if (tmp.length < 2) return Number(data);
    const type = tmp[0];
    const value = tmp[1];
    if (type === 'fl') {
        const buf = Buffer.from(value, 'hex');
        return Math.round(buf.readFloatBE(0) * 100) / 100;
    }
    if (['u8','u1','u3','u6'].includes(type)) return parseInt(value, 16);
    if (['i1','i3','i8'].includes(type)) return parseInt(value, 16);
    return Number(value);
}

// Shelly-ID Mapping (Gen1 roller/0/command/pos)
const devices = {
    east: [
        {name: 'Kueche2', shelly: 'shellyswitch25-1099F3'},
        {name: 'GaesteBad', shelly: 'shellyswitch25-109DA4'}
    ],
    west: [
        {name: 'Wohnzimmer1', shelly: 'shellyswitch25-10A277'}
    ]
};

const energy = msg.payload && msg.payload.ENERGY ? msg.payload.ENERGY : {};
const pvW = decodeSenecValue(energy.GUI_INVERTER_POWER);
const now = new Date();
const hour = now.getHours() + now.getMinutes() / 60;
const sunny = pvW >= cfg.shadeOnW;

let phase = 'none';
if (hour >= cfg.eastStartHour && hour < cfg.eastEndHour) phase = 'east';
else if (hour >= cfg.eastEndHour && hour < cfg.westEndHour) phase = 'west';

let commands = [];
const ts = now.toISOString();

if (sunny && phase === 'east') {
    for (const d of devices.east) {
        commands.push({
            topic: 'shellies/' + d.shelly + '/roller/0/command/pos',
            payload: cfg.shadePos
        });
    }
    node.warn(ts + ' OST-SCHATTEN: ' + devices.east.map(d=>d.name).join(',') + ' auf ' + cfg.shadePos + '% (PV=' + pvW + 'W)');
}

if (phase === 'west') {
    // Sonne ist nach Westen gewandert - Ostseite wieder oeffnen
    for (const d of devices.east) {
        commands.push({
            topic: 'shellies/' + d.shelly + '/roller/0/command/pos',
            payload: cfg.openPos
        });
    }
    if (sunny) {
        for (const d of devices.west) {
            commands.push({
                topic: 'shellies/' + d.shelly + '/roller/0/command/pos',
                payload: cfg.shadePos
            });
        }
        node.warn(ts + ' WEST-SCHATTEN: ' + devices.west.map(d=>d.name).join(',') + ' auf ' + cfg.shadePos + '% (PV=' + pvW + 'W)');
    }
}

if (hour >= cfg.westEndHour) {
    // Feierabend: alles oeffnen
    const all = [...devices.east, ...devices.west];
    for (const d of all) {
        commands.push({
            topic: 'shellies/' + d.shelly + '/roller/0/command/pos',
            payload: cfg.openPos
        });
    }
    node.warn(ts + ' ABEND: alles oeffnen');
}

node.status({
    fill: commands.length > 0 ? 'green' : 'blue',
    shape: 'dot',
    text: (commands.length > 0 ? '⚡' : '·') + ' PV=' + pvW + 'W ' + phase + (sunny?' sonnig':'') + ' | ' + commands.length + ' cmds'
});

if (commands.length === 0) return null;
return [commands];
